const req = $('Receive Delete Request').first().json;
return [{
  json: {
    client_id: 'caiac',
    timestamp: req.headers['x-caiac-timestamp'],
    signature: req.headers['x-caiac-signature'],
    token: (req.headers.authorization || '').replace(/^Bearer\s+/i, ''),
    webhook_secret: $input.first().json.webhook_secret
  }
}];

const session = $input.first().json;
if (session.is_caiac_staff !== true) {
  throw new Error('Forbidden: is_caiac_staff required');
}
return [{ json: { user_email: session.email, is_caiac_staff: true } }];

const validModes = ['test_data', 'by_email', 'by_source'];

// Detect trigger source:
//   Webhook path  → Receive Delete Request has the body
//   Manual path   → Set Input Params passes params directly as input
let body;
try {
  body = $('Receive Delete Request').first().json.body || {};
} catch (_) {
  body = $input.first().json;
}

const { client_slug, mode, email, source, dry_run } = body;

if (!client_slug) throw new Error('Missing required field: client_slug');
if (!mode || !validModes.includes(mode)) throw new Error(`Invalid mode. Must be one of: ${validModes.join(', ')}`);
if (mode === 'by_email' && !email) throw new Error('mode=by_email requires email field');
if (mode === 'by_source' && !source) throw new Error('mode=by_source requires source field');

return [{ json: { client_slug, mode, email: email || null, source: source || null, dry_run: dry_run === true } }];

const config = $input.first().json;
if (!config.client_id) throw new Error('Client not found');

const params = $('Parse and Validate Body').first().json;
let dbWhere, dbParams, sheetPattern;

if (params.mode === 'test_data') {
  dbWhere = `client_id = $1 AND source = 'test-suite'`;
  dbParams = [config.client_id];
  sheetPattern = { type: 'test_data' };
} else if (params.mode === 'by_email') {
  dbWhere = 'client_id = $1 AND email = $2';
  dbParams = [config.client_id, params.email];
  sheetPattern = { type: 'by_email', email: params.email };
} else {
  dbWhere = 'client_id = $1 AND source = $2';
  dbParams = [config.client_id, params.source];
  sheetPattern = { type: 'by_source', source: params.source };
}

return [{ json: {
  client_id: config.client_id,
  sheet_id: config.sheet_id,
  lead_sheet_tab: config.lead_sheet_tab || 'Lead Information',
  dbWhere, dbParams, sheetPattern,
  dry_run: params.dry_run
}}];

const leads = $input.all().map(i => i.json).filter(r => r.id);
const filter = $('Build Delete Filter').first().json;

if (leads.length === 0) {
  return [{ json: { action: 'no_leads', leads_found: 0, sheet_id: filter.sheet_id, lead_sheet_tab: filter.lead_sheet_tab, sheetPattern: filter.sheetPattern, dry_run: filter.dry_run } }];
}
if (filter.dry_run) {
  return [{ json: { action: 'dry_run', leads_found: leads.length, leads, sheet_id: filter.sheet_id, lead_sheet_tab: filter.lead_sheet_tab, sheetPattern: filter.sheetPattern, dry_run: true } }];
}
return [{ json: { action: 'delete', leads_found: leads.length, leads, sheet_id: filter.sheet_id, lead_sheet_tab: filter.lead_sheet_tab, sheetPattern: filter.sheetPattern, dry_run: false } }];

const rows = $input.all().map(i => i.json);
const pattern = $('Check Dry Run or Empty').first().json.sheetPattern;

function rowMatches(row) {
  const vals = Object.entries(row)
    .filter(([k]) => k !== 'row_number')
    .map(([, v]) => String(v || '').trim());
  if (pattern.type === 'test_data') {
    return vals.some(v => v.includes('@example.invalid') || v === '555-000-0002');
  }
  if (pattern.type === 'by_email') {
    return vals.some(v => v === pattern.email);
  }
  if (pattern.type === 'by_source') {
    return vals.some(v => v === pattern.source);
  }
  return false;
}

const matching = rows
  .filter(r => r.row_number && rowMatches(r))
  .sort((a, b) => b.row_number - a.row_number);

if (matching.length === 0) return [{ json: { row_number: null, _no_rows: true } }];
return matching.map(r => ({ json: r }));

const deleted = $input.all().map(i => i.json).filter(r => r.id);
return [{ json: {
  ok: true,
  leads_deleted: deleted.length,
  leads: deleted.map(r => ({ id: r.id, email: r.email, name: r.name })),
  sheet_rows_matched: $('Find Matching Sheet Rows').all().filter(i => !i.json._no_rows).length,
  client_slug: $('Parse and Validate Body').first().json.client_slug,
  mode: $('Parse and Validate Body').first().json.mode
}}];
